/* ─── TimelineViewer ─────────────────────────────────────────────────────────── */

.tlv {
  background: var(--surface, #f7f8fa);
  border: 1px solid var(--border, #e5e7eb);
  border-radius: var(--radius, 6px);
  padding: 20px 24px;
  outline: none; /* keyboard focus handled silently */
}

/* ── Header ──────────────────────────────────────────────────────────────────── */

.tlv__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 10px;
  margin-bottom: 16px;
}

.tlv__title {
  font-size: 15px;
  font-weight: 600;
  margin: 0;
  color: var(--text, #1f2328);
}

.tlv__nav {
  display: flex;
  align-items: center;
  gap: 12px;
}

.tlv__nav-btn {
  background: none;
  border: 1px solid var(--border, #e5e7eb);
  border-radius: var(--radius, 6px);
  padding: 4px 12px;
  font-size: 14px;
  cursor: pointer;
  color: var(--text, #1f2328);
  transition: background 0.15s, border-color 0.15s;
}

.tlv__nav-btn:hover:not(:disabled) {
  border-color: var(--accent, #3b82d4);
  color: var(--accent, #3b82d4);
}

.tlv__nav-btn:disabled {
  opacity: 0.35;
  cursor: default;
}

.tlv__week-label {
  font-size: 14px;
  font-weight: 500;
  color: var(--text, #1f2328);
  white-space: nowrap;
}

.tlv__timetable-name {
  font-weight: 400;
  color: var(--muted, #57606a);
}

/* ── Empty / placeholder ────────────────────────────────────────────────────── */

.tlv__empty {
  font-size: 14px;
  color: var(--muted, #57606a);
  font-style: italic;
}

/* ── Grid wrapper ──────────────────────────────────────────────────────────── */

.tlv__grid-wrapper {
  overflow-x: auto;
}

/* CSS Grid: time label + 7 day columns */
.tlv__grid {
  display: grid;
  grid-template-columns: 52px repeat(7, 1fr);
  border-left: 1px solid var(--border, #e5e7eb);
  border-top: 1px solid var(--border, #e5e7eb);
  min-width: 480px;
}

/* Header cells */
.tlv__header-cell {
  padding: 4px 2px;
  font-size: 11px;
  font-weight: 600;
  text-align: center;
  color: var(--muted, #57606a);
  background: var(--surface, #f7f8fa);
  border-right: 1px solid var(--border, #e5e7eb);
  border-bottom: 2px solid var(--border, #e5e7eb);
}

/* Time label cells */
.tlv__time-cell {
  font-size: 10px;
  color: var(--muted, #57606a);
  text-align: right;
  padding-right: 4px;
  line-height: 18px;
  height: 18px;
  border-right: 1px solid var(--border, #e5e7eb);
  border-bottom: 1px solid transparent;
  box-sizing: border-box;
}

/* Slot cells */
.tlv__cell {
  height: 18px;
  border-right: 1px solid var(--border, #e5e7eb);
  border-bottom: 1px solid transparent;
  box-sizing: border-box;
  background: #fff;
}

.tlv__cell--hour-start {
  border-bottom-color: var(--border, #e5e7eb);
}

/* ── Legend ─────────────────────────────────────────────────────────────────── */

.tlv__legend {
  display: flex;
  flex-wrap: wrap;
  gap: 6px 16px;
  margin-top: 12px;
  font-size: 12px;
  color: var(--muted, #57606a);
}

.tlv__legend-item {
  display: flex;
  align-items: center;
  gap: 5px;
}

.tlv__legend-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}

