  function handleOptimise() {
    // Validate: at least one subject needs improvement
    const hasGap = subjects.some(s => {
      const target = s.targetGrade ?? s.currentGrade
      return GRADE_POINTS[target] > GRADE_POINTS[s.currentGrade]
    })
    if (!hasGap) {
      alert('No subjects need improvement — set higher target grades in the Subjects & Grades tab.')
      return
    }

    // Validate: replaceable slots exist (free/rest/fun)
    const hasReplaceable = Object.values(timetable.days).some(day =>
      Object.values(day).some(
        slot => slot.activity === 'free' || slot.activity === 'rest' || slot.activity === 'fun'
      )
    )
    if (!hasReplaceable) {
      alert('No free, rest, or fun slots available to replace.')
      return
    }

    const ok = window.confirm(
      'This will replace free/rest/fun slots to fit your target grades. Continue?'
    )
    if (!ok) return

    const { efficiency } = computeBalanceStats(hourTotals)
    const optimised = optimiseTimetable(timetable, subjects, totalWeeks, efficiency, weekdayBias)
    onTimetableChange(optimised)
  }

  // ── Render ────────────────────────────────────────────────────────────────────

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', minHeight: 0 }}>
      {/* Controls */}
      <div className="tg-controls">
        <button className="tg-clear-btn" onClick={handleClearAll}>
          Clear All
        </button>

        <div className="tg-optimise-group">
          <label className="tg-bias-label">
            Weekday bias: {weekdayBias}×
            <input
              type="range"
              className="tg-bias-slider"
              min={1}
              max={10}
              step={1}
              value={weekdayBias}
              onChange={e => setWeekdayBias(Number(e.target.value))}
            />
          </label>
          <button className="tg-optimise-btn" onClick={handleOptimise}>
            ✨ Optimise
          </button>
        </div>
      </div>

      {/* Scrollable grid */}
      <div className="tg-scroll">
        <div className="timetable-grid">

          {/* Header row */}
          <div className="tg-header-cell" /> {/* corner spacer */}
          {DAY_NAMES.map(day => (
            <div key={day} className="tg-header-cell">{day}</div>
          ))}

          {/* Slot rows */}
          {Array.from({ length: slotCount }, (_, slotIndex) => {
            const label = slotTimeLabel(slotIndex, startHour)
            const isHourStart = slotIndex % 4 === 0

            return (
              <React.Fragment key={slotIndex}>
                {/* Time label */}
                <div className="tg-time-label">
                  {label ?? ''}
                </div>

                {/* Day cells */}
                {DAY_NAMES.map(day => {
                  const slot = timetable.days[day]?.[slotIndex]
                  const colour = slot?.activity ? (activityColours[slot.activity] ?? '#ccc') : undefined

                  return (
                    <div
                      key={`${day}-${slotIndex}`}
                      className={`tg-cell${isHourStart ? ' tg-cell--hour-start' : ''}`}
                      style={colour ? { backgroundColor: colour } : undefined}
                      onMouseDown={() => handleMouseDown(day, slotIndex)}
                      onMouseEnter={() => handleMouseEnter(day, slotIndex)}
                    />
                  )
                })}
              </React.Fragment>
            )
          })}

        </div>

        {/* Colour legend */}
        {legendItems.length > 0 && (
          <div className="tg-legend">
            {legendItems.map(item => (
              <div key={item.id} className="tg-legend-item">
                <div className="tg-legend-dot" style={{ backgroundColor: item.colour }} />
                {item.label}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

