  timetable,
  onTimetableChange,
  startHour,
  endHour,
  selectedActivity,
  activityColours,
  legendItems,
  subjects,
  totalWeeks,
  hourTotals,
}: TimetableGridProps) {
  const [weekdayBias, setWeekdayBias] = useState(2)

  // ── Range-fill state ─────────────────────────────────────────────────────────
