      <header className="app-header">
        <h1 className="app-title">Timetable &amp; Grade Predictor</h1>
        <button
          className="cog-btn"
          aria-label="Open settings"
          title="Settings"
          onClick={() => setShowSetupModal(true)}
        >
          ⚙
        </button>
