import React, { useState, useRef, useEffect, useCallback } from 'react'
import './TimetableGrid.css'
import type { Timetable, DayName, Subject } from '../types'
import { DAY_NAMES, createEmptyTimetable } from '../types'
import { optimiseTimetable } from '../utils/optimiserUtils'
import { computeBalanceStats, GRADE_POINTS } from '../utils/gradePredictor'
import type { HourTotals } from '../utils/timetableUtils'

// ── Props ──────────────────────────────────────────────────────────────────────

export interface TimetableGridProps {
  timetable: Timetable
  onTimetableChange: (t: Timetable) => void
  startHour: number
  endHour: number
  selectedActivity: string | null // null = eraser
  activityColours: Record<string, string>
  legendItems: { id: string; label: string; colour: string }[]
  subjects: Subject[]
  totalWeeks: number
  hourTotals: HourTotals
}

// ── Helpers ────────────────────────────────────────────────────────────────────

/** Pad a number to two digits. */
function pad(n: number): string {
  return String(n).padStart(2, '0')
}

/** Format a time label for a slot index (null if not on the hour). */
function slotTimeLabel(slotIndex: number, startHour: number): string | null {
  if (slotIndex % 4 === 0) {
    const hour = startHour + slotIndex / 4
    return `${pad(hour)}:00`
  }
  return null
}

/** Paint a single slot into a timetable immutably. */
function paintSlot(
  timetable: Timetable,
  day: DayName,
  slotIndex: number,
  activity: string | null,
): Timetable {
  const daySchedule = { ...timetable.days[day] }
  if (activity === null) {
    delete daySchedule[slotIndex]
  } else {
    daySchedule[slotIndex] = { activity: activity as import('../types').ActivityType }
  }
  return {
    ...timetable,
    days: { ...timetable.days, [day]: daySchedule },
  }
}

// ── Range-fill helper ──────────────────────────────────────────────────────────

/**
 * Fill a rectangular region of the timetable (days from dayA→dayB, slots from
 * slotA→slotB inclusive). When overwrite=false, only empty slots are painted.
 */
function rangeFill(
  timetable: Timetable,
  dayA: DayName,
  slotA: number,
  dayB: DayName,
  slotB: number,
  activity: string | null,
  overwrite: boolean,
): Timetable {
  const dayStart = Math.min(DAY_NAMES.indexOf(dayA), DAY_NAMES.indexOf(dayB))
  const dayEnd   = Math.max(DAY_NAMES.indexOf(dayA), DAY_NAMES.indexOf(dayB))
  const slotMin  = Math.min(slotA, slotB)
  const slotMax  = Math.max(slotA, slotB)

  let result = timetable
  for (let di = dayStart; di <= dayEnd; di++) {
    const day = DAY_NAMES[di]
    const daySchedule = { ...result.days[day] }
    for (let si = slotMin; si <= slotMax; si++) {
      const existing = daySchedule[si]?.activity ?? null
      if (!overwrite && existing !== null) continue // skip filled slots
      if (activity === null) {
        delete daySchedule[si]
      } else {
        daySchedule[si] = { activity: activity as import('../types').ActivityType }
      }
    }
    result = { ...result, days: { ...result.days, [day]: daySchedule } }
  }
  return result
}

// ── Component ──────────────────────────────────────────────────────────────────

export default function TimetableGrid({
  timetable,
  onTimetableChange,
  startHour,
  endHour,
  selectedActivity,
  activityColours,
  legendItems,
  subjects,
  totalWeeks,
  hourTotals,
}: TimetableGridProps) {
  const [weekdayBias, setWeekdayBias] = useState(2)

