/* ── Difficulty segmented control ────────────────────────────────────────── */
.sm-difficulty {
  display: flex;
  flex-shrink: 0;
  border: 1px solid var(--border, #e5e7eb);
  border-radius: 4px;
  overflow: hidden;
}

.sm-difficulty__btn {
  flex: 1;
  padding: 3px 7px;
  font-size: 11px;
  font-weight: 500;
  background: none;
  border: none;
  border-right: 1px solid var(--border, #e5e7eb);
  color: var(--muted, #57606a);
  cursor: pointer;
  transition: background 0.12s, color 0.12s;
  white-space: nowrap;
}

.sm-difficulty__btn:last-child {
  border-right: none;
}

.sm-difficulty__btn--active.sm-difficulty__btn--easy {
  background: #dcfce7;
  color: #15803d;
}

.sm-difficulty__btn--active.sm-difficulty__btn--medium {
  background: #fef9c3;
  color: #854d0e;
}

.sm-difficulty__btn--active.sm-difficulty__btn--hard {
  background: #fee2e2;
  color: #b91c1c;
}

