/* SubjectManager — full-page subject CRUD panel */

.subject-manager {
  padding: 24px;
  max-width: 800px;
}

.subject-manager__title {
  font-size: 20px;
  font-weight: 600;
  margin: 0 0 6px;
  color: var(--text, #1f2328);
}

.subject-manager__hint {
  font-size: 13px;
  color: var(--muted, #57606a);
  margin: 0 0 20px;
}

.subject-manager__empty {
  font-size: 14px;
  color: var(--muted, #57606a);
  font-style: italic;
  margin-bottom: 12px;
}

/* ── Subject row ──────────────────────────────────────────────────────── */
.subject-manager__list {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin-bottom: 16px;
}

.sm-row {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 12px;
  background: var(--surface, #f7f8fa);
  border: 1px solid var(--border, #e5e7eb);
  border-radius: 6px;
}

/* ── Colour swatch circle ─────────────────────────────────────────────── */
.sm-swatch {
  width: 18px;
  height: 18px;
  border-radius: 50%;
  flex-shrink: 0;
  border: 1px solid rgba(0, 0, 0, 0.12);
}

/* ── Name input ───────────────────────────────────────────────────────── */
.sm-name-input {
  flex: 1;
  font-size: 14px;
  border: 1px solid var(--border, #e5e7eb);
  border-radius: 4px;
  padding: 4px 8px;
  background: #fff;
  color: var(--text, #1f2328);
  min-width: 0;
}

.sm-name-input:focus {
  outline: none;
  border-color: var(--accent, #3b82d4);
  box-shadow: 0 0 0 2px rgba(59, 130, 212, 0.2);
}

/* ── Grade label+select ───────────────────────────────────────────────── */
.sm-grade-label {
  display: flex;
  align-items: center;
  gap: 5px;
  flex-shrink: 0;
}

.sm-grade-label__text {
  font-size: 12px;
  color: var(--muted, #57606a);
}

.sm-grade-select {
  font-size: 13px;
  border: 1px solid var(--border, #e5e7eb);
  border-radius: 4px;
  padding: 3px 6px;
  background: #fff;
  color: var(--text, #1f2328);
  cursor: pointer;
}

/* Target grade select gets a subtle purple tint to distinguish from current grade */
.sm-grade-select--target {
  border-color: var(--secondary, #7c5cd8);
  color: var(--secondary, #7c5cd8);
}

/* ── Colour label+input ───────────────────────────────────────────────── */
.sm-colour-label {
  display: flex;
  align-items: center;
  gap: 5px;
  flex-shrink: 0;
}

.sm-colour-label__text {
  font-size: 12px;
  color: var(--muted, #57606a);
}

.sm-colour-input {
  width: 32px;
  height: 32px;
  padding: 0;
  border: none;
  background: none;
  cursor: pointer;
}

/* ── Delete button ────────────────────────────────────────────────────── */
.sm-delete-btn {
  font-size: 13px;
  color: var(--muted, #57606a);
  background: none;
  border: 1px solid var(--border, #e5e7eb);
  border-radius: 4px;
  padding: 3px 8px;
  cursor: pointer;
  flex-shrink: 0;
}

.sm-delete-btn:hover {
  color: #c0392b;
  border-color: #c0392b;
  background: #fdf3f2;
}

/* ── Add button ───────────────────────────────────────────────────────── */
.sm-add-btn {
  font-size: 14px;
  color: var(--accent, #3b82d4);
  background: none;
  border: 1px dashed var(--accent, #3b82d4);
  border-radius: 5px;
  padding: 8px 16px;
  cursor: pointer;
  width: 100%;
  text-align: center;
}

.sm-add-btn:hover {
  background: #e8f0fe;
}

