                        {changed && whatIfPredicted > actualPredicted ? ' ▲' : changed ? ' ▼' : ''}
                      </span>
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>

          <button className="wip__reset" onClick={handleReset}>
            Reset all sliders
          </button>
        </div>
      )}
    </section>
  )
}

