import { useState } from 'react'
import './SubjectManager.css'
import type { Subject, UKGrade, SubjectDifficulty, GradeSnapshot } from '../types'

const UK_GRADES: UKGrade[] = ['A*', 'A', 'B', 'C', 'D', 'E', 'U']

const PRESET_COLOURS = [
