  '#C0392B', '#1ABC9C', '#F39C12', '#2C3E50', '#7F8C8D',
]

function randomPresetColour(): string {
  return PRESET_COLOURS[Math.floor(Math.random() * PRESET_COLOURS.length)]
}

function todayISO() {
  return new Date().toISOString().slice(0, 10)
}

