  const commitChange = useCallback((current: Timetable, next: Timetable) => {
    undoStack.current = [...undoStack.current.slice(-UNDO_LIMIT + 1), current]
    redoStack.current = []
    setCanUndo(true)
    setCanRedo(false)
    onTimetableChange(next)
  }, [onTimetableChange])

