      setCopiedDay(null)
    }
  }

  // ── Undo / redo ───────────────────────────────────────────────────────────────

  function handleUndo() {
    if (undoStack.current.length === 0) return
    const prev = undoStack.current[undoStack.current.length - 1]
    undoStack.current = undoStack.current.slice(0, -1)
