  height: 20px;
  line-height: 20px;
  user-select: none;
  position: sticky;
  left: 0;
  background: #fff;
  z-index: 1;
}

/* ─── Slot cells ───────────────────────────────────────────────────────────── */
.tg-cell {
  height: 20px;
  cursor: crosshair;
  user-select: none;
  border-right: 1px solid #f0f0f0;
  border-bottom: 1px solid #f0f0f0;
  box-sizing: border-box;
}

/* Slightly more visible top-border at the start of each hour */
.tg-cell--hour-start {
  border-top: 1px solid #ddd;
