  grid-template-columns: 52px repeat(7, 1fr);
  width: 100%;
  min-width: 480px;
}

/* ─── Header row ───────────────────────────────────────────────────────────── */
.tg-header-cell {
  text-align: center;
  font-size: 11px;
  font-weight: 600;
  color: var(--text-muted);
  padding: 4px 0;
  border-bottom: 2px solid var(--border);
  position: sticky;
  top: 0;
  background: var(--bg, #fff);
  z-index: 2;
}

/* Top-left corner spacer */
.tg-header-cell:first-child {
  border-bottom-color: transparent;
}

/* ─── Time label column ────────────────────────────────────────────────────── */
.tg-time-label {
  text-align: right;
  font-size: 11px;
  color: var(--text-muted);
  padding-right: 6px;
  height: 20px;
  line-height: 20px;
  user-select: none;
  position: sticky;
  left: 0;
  background: var(--bg, #fff);
  z-index: 1;
}

/* ─── Slot cells ───────────────────────────────────────────────────────────── */
.tg-cell {
  height: 20px;
  cursor: crosshair;
  user-select: none;
  border-right: 1px solid var(--border, #f0f0f0);
  border-bottom: 1px solid var(--border, #f0f0f0);
  box-sizing: border-box;
  background: var(--bg, #fff);
}

/* Slightly more visible top-border at the start of each hour */
.tg-cell--hour-start {
  border-top: 1px solid var(--border, #ddd);
}

/* Locked slot — diagonal stripe overlay */
.tg-cell--locked::after {
  content: '';
  position: absolute;
  inset: 0;
  background: repeating-linear-gradient(
    -45deg,
    rgba(0,0,0,0.18) 0px,
    rgba(0,0,0,0.18) 2px,
    transparent 2px,
    transparent 6px
  );
  pointer-events: none;
}

.tg-cell--locked {
  position: relative;
}

/* Copied day header */
.tg-header-cell--copied {
  background: #e8f0fe !important;
  border-bottom-color: var(--accent, #3b82d4) !important;
  color: var(--accent, #3b82d4);
}

/* Undo / redo buttons */
.tg-undo-btn {
  background: none;
  border: 1px solid var(--border, #e5e7eb);
  border-radius: var(--radius, 6px);
  padding: 4px 10px;
  font-size: 13px;
  color: var(--text-muted, #57606a);
  cursor: pointer;
  transition: color 0.15s, border-color 0.15s;
}

.tg-undo-btn:hover:not(:disabled) {
  color: var(--text, #1f2328);
  border-color: var(--text-muted, #57606a);
}

.tg-undo-btn:disabled {
  opacity: 0.35;
  cursor: default;
}

/* Hint bar */
.tg-hint {
  font-size: 12px;
  color: var(--muted, #57606a);
  background: #fef9c3;
  border-bottom: 1px solid #fde047;
  padding: 4px 12px;
  flex-shrink: 0;
}

/* Range-fill anchor: pulsing outline so user knows the first point is set */
.tg-cell--anchor {
  outline: 2px solid #7c5cd8;
  outline-offset: -2px;
  z-index: 1;
  position: relative;
  animation: tg-anchor-pulse 0.9s ease-in-out infinite alternate;
}

@keyframes tg-anchor-pulse {
  from { outline-color: #7c5cd8; }
  to   { outline-color: #b39ddb; }
}

/* ─── Colour legend ────────────────────────────────────────────────────────── */
.tg-legend {
  display: flex;
  flex-wrap: wrap;
  gap: 6px 12px;
  padding: 8px 4px;
  border-top: 1px solid #e5e7eb;
  flex-shrink: 0;
}

.tg-legend-item {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 11px;
  color: #57606a;
}

.tg-legend-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}

