            />
            <GradePredictor
              subjects={subjects}
              totals={hourTotals}
              totalWeeks={totalWeeks}
            />
            <WhatIfPanel
              subjects={subjects}
              totals={hourTotals}
              totalWeeks={totalWeeks}
            />
            <TimelineViewer
              weekPlan={weekPlan}
              timetables={timetables}
              startHour={settings.startHour}
              endHour={settings.endHour}
              activityColours={activityColours}
              legendItems={legendItems}
            />
          </div>
        )}
      </main>
    </div>
  )
}

export default App
